					<!-- ең°еӣҫжҳҫзӨә -->
					<map 
						v-if="disputeInfo.location?.latitude" 
						:latitude="disputeInfo.location.latitude" 
						:longitude="disputeInfo.location.longitude"
						:markers="markers"
						class="map-view">
					</map>
				</view>
			</view>
			
			<!-- еҺҶеҸІеӣһи®ҝж—¶й—ҙзәҝ -->
			<view v-if="feedbacks.length > 0" class="timeline-section">
				<view class="section-title">еӣһи®ҝи®°еҪ•</view>
				<view class="timeline">
					<view v-for="(feedback, index) in feedbacks" :key="feedback._id" class="timeline-item">
						<view class="timeline-dot"></view>
						<view class="timeline-content">
							<view class="timeline-header">
								<text class="timeline-time">{{ formatDateTime(feedback.feedback_time) }}</text>
								<text class="tag" :class="getResultClass(feedback.result)">{{ feedback.result }}</text>
							</view>
							<view class="timeline-body">
								<view class="timeline-row">
									<text class="label">еӣһи®ҝж–№ејҸпјҡ</text>
									<text>{{ feedback.type }}</text>
								</view>
								<view v-if="feedback.method" class="timeline-row">
									<text class="label">еӨ„зҗҶжҺӘж–Ҫпјҡ</text>
									<text>{{ feedback.method }}</text>
								</view>
								<view v-if="feedback.notes" class="timeline-row">
									<text class="label">еӨҮжіЁпјҡ</text>
									<text>{{ feedback.notes }}</text>
								</view>
								<view v-if="feedback.media && feedback.media.length > 0" class="timeline-media">
									<image 
										v-for="(media, idx) in feedback.media" 
										:key="idx"
										v-if="media.type === 'image'"
										:src="media.url"
										class="media-image"
										mode="aspectFill"
										@click="previewImage(media.url, feedback.media)" />
								</view>
							</view>
						</view>
					</view>
				</view>
			</view>
			
			<!-- еӣһи®ҝиЎЁеҚ•пјҲд»…зӨҫеҢәи§’иүІдё”зҠ¶жҖҒдёәеҫ…еӣһи®ҝжҲ–еӨ„зҗҶдёӯпјү -->
			<view v-if="userStore.isCommunity && canFeedback" class="feedback-section">
				<view class="section-title">жҸҗдәӨеӣһи®ҝ</view>
				<view class="form-card">
					<view class="form-item">
						<text class="form-label">еӣһи®ҝж–№ејҸ <text class="required">*</text></text>
						<radio-group @change="onTypeChange">
							<label v-for="(type, index) in typeOptions" :key="index" class="radio-item">
								<radio :value="type" :checked="feedbackForm.type === type" />
								<text>{{ type }}</text>
							</label>
						</radio-group>
					</view>
					
					<view class="form-item">
						<text class="form-label">еӣһи®ҝз»“жһң <text class="required">*</text></text>
						<radio-group @change="onResultChange">
							<label v-for="(result, index) in resultOptions" :key="index" class="radio-item">
								<radio :value="result" :checked="feedbackForm.result === result" />
								<text>{{ result }}</text>
							</label>
						</radio-group>
					</view>
					
