						<text class="form-label">еӨ„зҗҶжҺӘж–Ҫ</text>
						<textarea 
							class="textarea" 
							v-model="feedbackForm.method" 
							placeholder="иҜ·жҸҸиҝ°йҮҮеҸ–зҡ„еӨ„зҗҶжҺӘж–Ҫ"
							maxlength="500" />
					</view>
					
					<view class="form-item">
						<text class="form-label">еӨҮжіЁ</text>
						<textarea 
							class="textarea" 
							v-model="feedbackForm.notes" 
							placeholder="иҜ·иҫ“е…ҘеӨҮжіЁдҝЎжҒҜпјҲеҸҜйҖүпјү"
							maxlength="200" />
					</view>
					
					<view class="form-item">
						<text class="form-label">з…§зүҮ/еҪ•йҹі</text>
						<view class="media-upload">
							<view v-for="(media, index) in feedbackForm.media" :key="index" class="media-item">
								<image 
									v-if="media.type === 'image'"
									:src="media.url"
									class="media-preview"
									mode="aspectFill"
									@click="previewImage(media.url, feedbackForm.media)" />
								<view v-else class="media-preview audio-preview">
									<text class="audio-icon">рҹҺө</text>
									<text class="audio-name">{{ media.name || 'еҪ•йҹі' }}</text>
								</view>
								<view class="media-delete" @click="removeMedia(index)">Г—</view>
							</view>
							<view class="media-add" @click="chooseMedia">
								<text class="add-icon">+</text>
								<text class="add-text">ж·»еҠ </text>
							</view>
						</view>
					</view>
					
					<view class="form-item">
						<text class="form-label">дёӢж¬Ўеӣһи®ҝж—Ҙжңҹ</text>
						<picker 
							mode="date" 
							:value="feedbackForm.nextDate"
							:start="minDate"
							@change="onDateChange">
							<view class="picker-input">
								<text :class="{ placeholder: !feedbackForm.nextDate }">
									{{ feedbackForm.nextDate || 'йҖүжӢ©ж—ҘжңҹпјҲеҸҜйҖүпјү' }}
								</text>
								<text class="arrow">вҖә</text>
							</view>
						</picker>
					</view>
					
					<button class="btn-submit" @click="submitFeedback" :loading="submitting">
						{{ submitting ? 'жҸҗдәӨдёӯ...' : 'жҸҗдәӨеӣһи®ҝ' }}
					</button>
				</view>
			</view>
