	</view>
</template>

<script setup>
	import { ref, reactive, computed, onMounted } from 'vue'
	import { useUserStore } from '@/store/user'
	
	const userStore = useUserStore()
	
	const disputeId = ref('')
	const disputeInfo = ref({})
	const feedbacks = ref([])
	const logs = ref([])
	const loading = ref(false)
	
	const typeOptions = ['и§Ғйқў', 'з”өиҜқ']
	const resultOptions = ['е·ІеҢ–и§Ј', 'жңӘеҢ–и§Ј']
	
	const feedbackForm = reactive({
		type: '',
		result: '',
		method: '',
		notes: '',
		media: [],
		nextDate: ''
	})
	
	const submitting = ref(false)
	const minDate = computed(() => {
		const tomorrow = new Date()
		tomorrow.setDate(tomorrow.getDate() + 1)
		return tomorrow.toISOString().split('T')[0]
	})
	
	const markers = ref([])
	
	const canFeedback = computed(() => {
		return disputeInfo.value.status === 'еҫ…еӣһи®ҝ' || disputeInfo.value.status === 'еӨ„зҗҶдёӯ'
	})
	
	onMounted(() => {
		// иҺ·еҸ–йЎөйқўеҸӮж•°
		const pages = getCurrentPages()
		const currentPage = pages[pages.length - 1]
		disputeId.value = currentPage.options?.id || ''
		
		if (disputeId.value) {
			loadDetail()
		}
	})
	
	async function loadDetail() {
		loading.value = true
		try {
			const res = await uniCloud.callFunction({
				name: 'getDisputeDetail',
				data: {
					disputeId: disputeId.value
				}
			})
			
			if (res.result.success) {
				disputeInfo.value = res.result.data.dispute
				feedbacks.value = res.result.data.feedbacks
				logs.value = res.result.data.logs
				
				// и®ҫзҪ®ең°еӣҫж Үи®°
				if (disputeInfo.value.location?.latitude) {
					markers.value = [{
						id: 1,
						latitude: disputeInfo.value.location.latitude,
						longitude: disputeInfo.value.location.longitude,
						title: disputeInfo.value.location.address
					}]
				}
			} else {
				throw new Error(res.result.error || 'еҠ иҪҪеӨұиҙҘ')
			}
		} catch (e) {
			console.error('еҠ иҪҪиҜҰжғ…еӨұиҙҘ', e)
			uni.showToast({
				title: e.message || 'еҠ иҪҪеӨұиҙҘ',
				icon: 'none'
			})
		} finally {
			loading.value = false
		}
	}
	
	function onTypeChange(e) {
		feedbackForm.type = e.detail.value
	}
	
	function onResultChange(e) {
		feedbackForm.result = e.detail.value
	}
	
	function onDateChange(e) {
		feedbackForm.nextDate = e.detail.value
	}
	
	async function chooseMedia() {
		try {
			const res = await uni.chooseMedia({
				count: 9 - feedbackForm.media.length,
				mediaType: ['image', 'video'],
				sourceType: ['camera', 'album']
			})
			
			// дёҠдј еҲ°дә‘еӯҳеӮЁ
			for (let tempFile of res.tempFiles) {
				const uploadRes = await uniCloud.uploadFile({
					filePath: tempFile.tempFilePath,
					cloudPath: `feedback/${Date.now()}_${Math.random().toString(36).substr(2, 9)}.${tempFile.tempFilePath.split('.').pop()}`
				})
				
				feedbackForm.media.push({
					type: tempFile.fileType === 'image' ? 'image' : 'audio',
					url: uploadRes.fileID,
					name: tempFile.name
				})
			}
		} catch (e) {
			console.error('йҖүжӢ©еӘ’дҪ“еӨұиҙҘ', e)
			if (e.errMsg && !e.errMsg.includes('cancel')) {
				uni.showToast({
					title: 'йҖүжӢ©еӨұиҙҘ',
					icon: 'none'
				})
			}
		}
	}
	
	function removeMedia(index) {
		feedbackForm.media.splice(index, 1)
	}
	
	function previewImage(current, urls) {
		const imageUrls = urls.filter(m => m.type === 'image').map(m => m.url)
		uni.previewImage({
			current: current,
			urls: imageUrls
		})
	}
	
	async function submitFeedback() {
		// иЎЁеҚ•йӘҢиҜҒ
		if (!feedbackForm.type) {
			uni.showToast({
				title: 'иҜ·йҖүжӢ©еӣһи®ҝж–№ејҸ',
				icon: 'none'
			})
			return
		}
		
		if (!feedbackForm.result) {
			uni.showToast({
				title: 'иҜ·йҖүжӢ©еӣһи®ҝз»“жһң',
				icon: 'none'
			})
			return
		}
		
		submitting.value = true
		
		try {
			const res = await uniCloud.callFunction({
				name: 'submitFeedback',
				data: {
					disputeId: disputeId.value,
					feedbackData: {
						type: feedbackForm.type,
						result: feedbackForm.result,
						method: feedbackForm.method,
						notes: feedbackForm.notes,
						media: feedbackForm.media,
						next_date: feedbackForm.nextDate
					},
					userInfo: {
						openid: userStore.openid,
						name: userStore.name
					}
				}
			})
			
			if (res.result.success) {
				uni.showToast({
					title: 'жҸҗдәӨжҲҗеҠҹ',
					icon: 'success'
				})
				
				// жё…з©әиЎЁеҚ•
				feedbackForm.type = ''
				feedbackForm.result = ''
				feedbackForm.method = ''
				feedbackForm.notes = ''
				feedbackForm.media = []
				feedbackForm.nextDate = ''
				
				// йҮҚж–°еҠ иҪҪиҜҰжғ…
				setTimeout(() => {
					loadDetail()
				}, 1500)
			} else {
				throw new Error(res.result.error || 'жҸҗдәӨеӨұиҙҘ')
			}
		} catch (e) {
			console.error('жҸҗдәӨеӣһи®ҝеӨұиҙҘ', e)
			uni.showToast({
				title: e.message || 'жҸҗдәӨеӨұиҙҘ',
				icon: 'none'
			})
		} finally {
			submitting.value = false
		}
	}
	
	function formatDateTime(timestamp) {
		if (!timestamp) return ''
		const date = new Date(timestamp)
		const year = date.getFullYear()
		const month = String(date.getMonth() + 1).padStart(2, '0')
		const day = String(date.getDate()).padStart(2, '0')
		const hours = String(date.getHours()).padStart(2, '0')
		const minutes = String(date.getMinutes()).padStart(2, '0')
		return `${year}-${month}-${day} ${hours}:${minutes}`
	}
	
	function getStatusClass(status) {
		const map = {
			'еҫ…еҲҶжҙҫ': 'status-pending',
			'еҫ…еӣһи®ҝ': 'status-pending',
			'еӨ„зҗҶдёӯ': 'status-processing',
			'е·ІеҢ–и§Ј': 'status-resolved',
			'е·Іе…ій—ӯ': 'status-closed'
		}
		return map[status] || ''
	}
	
	function getUrgencyClass(urgency) {
		const map = {
			'дёҖиҲ¬': 'tag-primary',
			'зҙ§жҖҘ': 'tag-warning',
			'зү№жҖҘ': 'tag-danger'
		}
		return map[urgency] || ''
	}
	
	function getResultClass(result) {
		return result === 'е·ІеҢ–и§Ј' ? 'tag-success' : 'tag-warning'
	}

	// еҲҶдә«з»ҷжңӢеҸӢ
	const onShareAppMessage = () => {
		return {
			title: `зә зә·иҜҰжғ…пјҡ${disputeInfo.value.title || 'зҹӣзӣҫзә зә·'}`,
			path: `/pages/detail/index?id=${disputeId.value}`,
			desc: 'жҹҘзңӢзҹӣзӣҫзә зә·иҜҰжғ…е’ҢеӨ„зҗҶи®°еҪ•',
			imageUrl: '/static/logo.png'
		}
	}

	defineExpose({
		onShareAppMessage
	})
</script>

